const orcamento = $json.body || {};
const cliente = orcamento.cliente || {};
const dados_eletricos = orcamento.dados_eletricos || {};
const dados_conta = orcamento.dados_conta || {};
const calc = orcamento.dimensionamento_backup_calculado || {};
const financeiro = orcamento.financeiro || {};
const compliance = orcamento.compliance_killcritic || {};
const cargas = orcamento.cargas_criticas || [];

// Renderizar Cargas Críticas em formato lista Markdown
const cargas_md = cargas.map(c => {
  const motor_text = c.motor ? ' | *Motor com pico de partida (requer análise)*' : '';
  return `- **${c.nome_carga}**: ${c.potencia_w} W | Qtd: ${c.quantidade} | Uso diário: ${c.horas_uso_diario}h${motor_text}`;
}).join('\n');

// Renderizar Pendências em formato lista Markdown
const pendencias_md = compliance.pendencias_criticas.map(p => `- [ ] ${p}`).join('\n');
const bloqueios_md = compliance.motivos_bloqueio.map(b => `- ${b}`).join('\n');

// Renderizar Baterias sugeridas
const baterias_sugeridas = calc.baterias_sugeridas || [];
const baterias_md = baterias_sugeridas.map(b => `${b.quantidade}x ${b.modelo} (Capacidade total de ${calc.bateria_nominal_kwh} kWh)`).join(', ') || 'Pendente definição';

// 1. TEMPLATE CLIENTE
const md_cliente = `# PROPOSTA COMERCIAL PRELIMINAR — SOLUÇÃO ECOVOLT (SOLAR HÍBRIDO & BACKUP DE BATERIAS)
**Protocolo:** ${orcamento.protocolo}
**Data de Emissão:** ${new Date().toLocaleDateString('pt-BR')}

---

## 1. TÍTULO
**Estudo de Pré-Dimensionamento de Sistema Solar Fotovoltaico Híbrido com Armazenamento de Energia para Cargas Críticas**

## 2. IDENTIFICAÇÃO DO CLIENTE
- **Cliente / Condomínio:** ${cliente.nome}
- **Tipo de Cliente:** ${cliente.tipo_cliente}
- **Responsável / Decisor:** ${cliente.responsavel}
- **Local de Instalação:** ${cliente.endereco}, ${cliente.bairro} - ${cliente.cidade}/RJ
- **Contato:** ${cliente.whatsapp} / ${cliente.email}

## 3. OBJETIVO DA SOLUÇÃO
Prover resiliência energética contínua para cargas essenciais do cliente por meio de armazenamento de bateria de lítio integrado a sistema gerador fotovoltaico híbrido. O foco reside na autonomia durante falhas da concessionária de energia e na otimização do perfil de consumo, operando de forma autônoma e segura.

## 4. DIAGNÓSTICO PRELIMINAR
Com base no histórico médio de consumo de **${dados_conta.consumo_mensal_kwh} kWh/mês** e no custo financeiro informado, identificou-se a demanda para contingência das cargas críticas pré-selecionadas e a viabilidade técnica de microgeração fotovoltaica complementar para redução do consumo elétrico da rede da concessionária.

## 5. PREMISSAS TÉCNICAS
- **Tensão de Atendimento:** ${dados_eletricos.tensao} V
- **Padrão de Ligação:** ${dados_eletricos.tipo_ligacao}
- **Disjuntor Geral:** ${dados_eletricos.disjuntor_geral} A
- **Autonomia de Backup Solicitada:** ${orcamento.autonomia_desejada_horas} horas
- **Parâmetros Técnicos Básicos:** Eficiência do sistema de 85% e Profundidade de Descarga (DoD) de 80% para baterias de fosfato de ferro-lítio (LFP).

## 6. CARGAS CRÍTICAS CONSIDERADAS
Lista de cargas essenciais integradas ao circuito de backup preliminar:
${cargas_md}
- **Potência Crítica Instalada:** ${calc.potencia_critica_total_kw} kW
- **Potência de Simultaneidade Estimada:** ${calc.potencia_critica_simultanea_kw} kW
- **Consumo Energético Diário Crítico:** ${calc.energia_critica_diaria_kwh} kWh/dia

## 7. ESTIMATIVA DE SISTEMA SOLAR
- **Arranjo Fotovoltaico Preliminar:** ${orcamento.dimensionamento_solar_calculado ? orcamento.dimensionamento_solar_calculado.sistema_solar_kwp_preliminar : 0} kWp
- **Geração Média Estimada:** ${orcamento.dimensionamento_solar_calculado ? orcamento.dimensionamento_solar_calculado.geracao_mensal_estimada_kwh : 0} kWh/mês
- **Redução Estimada de Consumo:** Estimativa de redução de consumo da rede da concessionária, sujeita à análise final da conta de energia, irradiação local efetiva, perfil de consumo de cargas, homologação e tarifas. **Não há promessa ou garantia de economia fixa.**

## 8. ESTIMATIVA DE BACKUP COM BATERIAS
- **Energia Útil Necessária:** ${calc.bateria_util_kwh} kWh (para suprir a autonomia durante ausência de sol)
- **Energia Nominal do Banco:** ${calc.bateria_nominal_kwh} kWh
- **Margem de Segurança Técnica Aplicada:** ${((calc.paramentos_calculo || {}).margem_tecnica * 100) || 25}%
- **Capacidade de Descarga Suportada:** ${calc.bateria_capacidade_descarga_kw} kW contínuos

## 9. EQUIPAMENTOS PRINCIPAIS SUGERIDOS (CORSOLAR / SOLAXPOWER)
- **Inversor Híbrido:** ${calc.inversor_sugerido} (SolaXPower Híbrido)
- **Módulos de Armazenamento:** Bateria Triple Power LFP (capacidade total aproximada de ${calc.bateria_nominal_kwh} kWh - sugerido: ${baterias_md})
- *Obs: Modelos, quantidades e capacidades definitivos estão sujeitos à validação comercial e estoque de fornecedores no momento do fechamento.*

## 10. ESCOPO DE FORNECIMENTO
- Equipamento inversor híbrido inteligente.
- Banco de baterias de lítio Triple Power (LFP) com módulo BMS integrado.
- Módulos solares fotovoltaicos de silício monocristalino de alta eficiência.
- Estrutura de fixação mecânica e String Box de proteção (CC/CA).

## 11. ESCOPO DE INSTALAÇÃO
- Engenharia e projeto de adequação física do espaço.
- Fixação mecânica e elétrica dos inversores, baterias e módulos.
- Lançamento de cabos de potência e conexões.
- Parametrização e ativação operacional do sistema híbrido.

## 12. EXCLUSÕES
- Adequações estruturais de telhados, reforço de lajes ou remoção de obstáculos físicos (árvores, antenas).
- Modificações no padrão de entrada da concessionária que superem o disjuntor geral existente.
- Alimentação de cargas pesadas não críticas (como fornos elétricos, chapas, resistências elétricas, fritadeiras ou ar-condicionado central).

## 13. PENDÊNCIAS PARA CONFIRMAÇÃO
As pendências críticas identificadas que bloqueiam a emissão de uma proposta comercial final são:
${pendencias_md}

## 14. OBSERVAÇÕES TÉCNICAS (OBRIGATÓRIO)
> **[!IMPORTANT]**
> **Dimensionamento preliminar sujeito à Avaliação Técnica, análise da conta de energia, confirmação das cargas críticas, tensão de atendimento, local de instalação e compatibilidade dos equipamentos.**

## 15. CONDIÇÕES COMERCIAIS
- **Valor Estimado Preliminar:** R$ ${(financeiro.valor_final_estimado || 0).toFixed(2)}
- **Validade do Estudo:** 10 dias corridos a partir desta emissão.
- **Tipo de Orçamento:** Pré-dimensionamento. O preço final e o cronograma de instalação definitiva serão definidos em proposta final após a realização de Avaliação Técnica presencial obrigatória.

## 16. CONCLUSÃO
Este pré-dimensionamento visa fundamentar as discussões sobre o investimento técnico em resiliência de energia para o condomínio/estabelecimento. Convidamos o responsável para agendamento de uma **Avaliação Técnica presencial** para validação física e elétrica dos pontos de rede.

## 17. DADOS DA DL
**DL Soluções Condominiais LTDA**
CNPJ: 37.953.703/0001-00
Rio de Janeiro - RJ
Fale com nosso consultor no Direct/WhatsApp.`;

// 2. TEMPLATE INTERNO
const md_interno = `# RELATÓRIO INTERNO DE ANÁLISE TÉCNICA E COMERCIAL — ECOVOLT
**Protocolo:** ${orcamento.protocolo}
**Versão Atual:** V1_gerada

---

## 1. CUSTOS INTERNOS
- **Custo Insumos / Equipamentos SolaX/Baterias:** R$ ${(financeiro.custos_estimados_equipamentos || 0).toFixed(2)}
- **Custo Logística / Impostos:** R$ ${(financeiro.logistica_impostos || 0).toFixed(2)}
- **Custo Instalação (Homem-Hora):** R$ ${(financeiro.custo_instalacao_estimado || 0).toFixed(2)}
- **Custo Total Estimado (C.O.GS):** R$ ${((financeiro.custos_estimados_equipamentos || 0) + (financeiro.logistica_impostos || 0) + (financeiro.custo_instalacao_estimado || 0)).toFixed(2)}

## 2. FORNECEDOR
- **Parceiro Fornecedor Principal:** Corsolar (SolaXPower Brasil)
- **Status:** Equipamento de referência preliminar marcado como pendente_validacao.

## 3. MODELO SUGERIDO
- **Inversor:** ${calc.inversor_sugerido}
- **Módulo Bateria:** ${baterias_md}

## 4. PREÇO MÁXIMO DE COMPRA
- **Inversor:** R$ ${(financeiro.custos_estimados_equipamentos * 0.45 || 0).toFixed(2)}
- **Bateria:** R$ ${(financeiro.custos_estimados_equipamentos * 0.55 || 0).toFixed(2)}

## 5. MARGEM
- **Margem Bruta:** ${financeiro.margem_bruta_porcentagem || 35}%
- **Markup:** ${(1 / (1 - ((financeiro.margem_bruta_porcentagem || 35) / 100))).toFixed(2)}
- **Valor de Venda Proposto:** R$ ${(financeiro.valor_final_estimado || 0).toFixed(2)}

## 6. RISCO TÉCNICO
- Verificação de padrão trifásico e QGBT.
- Avaliação física do peso das baterias Triple Power (sala técnica).
- Risco de sobrecarga por motores e bombas pesadas em paralelo.

## 7. RISCO COMERCIAL
- Flutuação cambial de custos na Corsolar.
- Expectativa de economia sem Avaliação Técnica.

## 8. PENDÊNCIAS COMERCIAIS
${pendencias_md}

## 9. ESTRATÉGIA DE NEGOCIAÇÃO
- Priorizar agendamento da Avaliação Técnica presencial.
- Focar no valor de contingência e resiliência (evitar focar apenas em desconto comercial).

## 10. HISTÓRICO DE VERSÕES
- V1: Versão automática gerada pelo Motor Solar.

## 11. RECOMENDAÇÃO KILLCRITIC
- **Auditoria:** ${compliance.status_killcritic}
- **Risco:** Risco ${compliance.risco_killcritic}
- **Motivos de Bloqueio:**
${bloqueios_md}`;

return {
  ...orcamento,
  proposta_markdown: {
    cliente: md_cliente,
    interna: md_interno
  },
  status: 'proposta_gerada'
};
